import React from 'react';
import { Card, CardContent, Box, Typography, Stack, CircularProgress, Chip } from '@mui/material';
import response from './response.json';

interface PackingItem {
  item: string;
  packed: boolean;
}

interface TripDetails {
  destination: string;
  departureDate: string;
  countdown: string;
  packingProgress: {
    itemsPacked: number;
    totalItems: number;
    percentagePacked: number;
  };
}

interface TripData {
  tripDetails: TripDetails;
  packingList: PackingItem[];
}

export default function Widget() {
  const { tripDetails, packingList } = response.data as TripData;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: theme === 'light' ? '#FFFFFF' : '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Next Trip to
            </Typography>
            <Typography variant="h5" fontWeight={600} sx={{ color: primaryColor }}>
              {tripDetails.destination}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Departure: {tripDetails.departureDate}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Countdown: {tripDetails.countdown}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Packing Progress
            </Typography>
            <Stack direction="row" alignItems="center" spacing={1}>
              <CircularProgress variant="determinate" value={tripDetails.packingProgress.percentagePacked} sx={{ color: accentColor }} />
              <Typography variant="body2" fontWeight={500}>
                {tripDetails.packingProgress.itemsPacked}/{tripDetails.packingProgress.totalItems} packed
              </Typography>
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Packing List
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {packingList.map((item, index) => (
                <Chip
                  key={index}
                  label={item.item}
                  sx={{
                    fontSize: '11px',
                    px: 1,
                    py: 0.5,
                    bgcolor: item.packed ? primaryColor : '#E0E0E0',
                    color: item.packed ? '#FFFFFF' : '#000000',
                  }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
